import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import Button from '@material-ui/core/Button';
import Grid from '@material-ui/core/Grid';
import CategorySelect from './CategorySelect';
import PlayerData from './PlayerData';
import ImageUpload from './ImageUpload';
import useStyles from './styles';

function AddUpdatePlayerForm({ player, handleSubmit, handleCloseUpdatePlayer }) {
  const classes = useStyles();
  const [playerData, setPlayerData] = useState({ name: '', club: '', infoEnglish: '', infoNorwegian: '', category: [] });
  const [imageFiles, setImageFiles] = useState([]);
  const [imagePreviews, setImagePreviews] = useState([]);
  const category = useSelector((state) => state.menus);
  const [selectedCategory, setSelectedCategory] = useState('');
  const [selectedSubCategories, setSelectedSubCategories] = useState([]);
  const [selectedSubCategoriesByCategory, setSelectedSubCategoriesByCategory] = useState({});
  const [selectedSubCategoriesByMainCategory, setSelectedSubCategoriesByMainCategory] = useState({});
  const [existingImages, setExistingImages] = useState([]);
  const [existingCategories, setExistingCategories] = useState([]);
  const [menuData, setMenuData] = useState({
    categories: [],
    subCategories: {},
  });

  // Fetch and update menu data when 'category' state changes
  useEffect(() => {
    const categories = category || [];
    const subCategories = {};

    // Organize categories and subcategories
    categories.forEach((cat) => {
      subCategories[cat.mainMenu] = cat.subMenu;
    });

    // Filter categories with subcategories
    const filteredCategories = categories.filter(
      (cat) => subCategories[cat.mainMenu].length > 0
    );

    setMenuData({
      categories: filteredCategories,
      subCategories,
    });
  }, [category]);

  // Fetch and update existing images when 'player' state changes
  useEffect(() => {
    if (player) {
      console.log("player: ", player)
      setPlayerData({
        name: player.name || '',
        club: player.club || '',
        infoEnglish: player.infoEnglish || '',
        infoNorwegian: player.infoNorwegian || '',
        category: player.category || [],
      });
      setExistingImages(player.images);
        // Kombinera befintliga kategorier och underkategorier till en enda array
        const combinedCategories = player.category.map((category, index) => ({
          main: category,
          sub: player.subCategory[index]
        }));
      
        // Sätt den kombinerade arrayen som existingCategories
        setExistingCategories(combinedCategories);
      
    }
  }, [player]);

  // Handle input change for player data fields
  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setPlayerData({
      ...playerData,
      [name]: value,
    });
  };

  // Handle category selection change
  const handleSelectChange = (event) => {
    const newSelectedCategory = event.target.value;
    setSelectedCategory(newSelectedCategory);
  
    // Hämta befintliga valda underkategorier för den nya huvudkategorin (om det finns några)
    const selectedSubCategoriesForNewCategory = selectedSubCategoriesByMainCategory[newSelectedCategory] || [];
    setSelectedSubCategories(selectedSubCategoriesForNewCategory);
  };

  // Handle image selection change
  const handleImageChange = (e) => {
    const files = Array.from(e.target.files);
    const previews = files.map((file) => URL.createObjectURL(file));

    setImageFiles([...imageFiles, ...files]);
    setImagePreviews([...imagePreviews, ...previews]);
    setPlayerData({ ...playerData, images: [...imageFiles, ...files] });
  };

  // Handle removal of an image preview
  const handleRemoveImage = (index) => {
    if (index < existingImages.length) {
      const updatedExistingImages = [...existingImages];
      updatedExistingImages.splice(index, 1);
      setExistingImages(updatedExistingImages);
    } else {
      const updatedFiles = [...imageFiles];
      const updatedPreviews = [...imagePreviews];

      const newIndex = index - existingImages.length;

      updatedFiles.splice(newIndex, 1);
      updatedPreviews.splice(newIndex, 1);

      setImageFiles(updatedFiles);
      setImagePreviews(updatedPreviews);
    }

    // Clear the value of the input field to remove the filename
    const fileInput = document.querySelector('input[type="file"]');
    if (fileInput) {
      fileInput.value = '';
    }
  };

  const handleSubCategoryChange = (event, mainCategory) => {
    const selectedSubCategoryValues = event.target.value;
    console.log("selectedSubCategoryValues: ", selectedSubCategoryValues)
    // Skapa en kopia av de tidigare valda underkategorierna för alla huvudkategorier
    const updatedSelectedSubCategories = { ...selectedSubCategoriesByMainCategory };
  
    // Uppdatera de valda underkategorierna för den aktuella huvudkategorin
    updatedSelectedSubCategories[mainCategory] = selectedSubCategoryValues;
  
    setSelectedSubCategoriesByMainCategory(updatedSelectedSubCategories);
  console.log("selectedSubCategoriesByMainCategory: ", selectedSubCategoriesByMainCategory)
    // Skapa en array för att hålla alla valda underkategorier för formuläret (inklusive huvud- och underkategorier)
    const updatedSelectedSubCategoriesForForm = [];
    for (const category in updatedSelectedSubCategories) {
      const subCategories = updatedSelectedSubCategories[category];
      subCategories.forEach(subCategory => {
        updatedSelectedSubCategoriesForForm.push({
          main: category,
          sub: subCategory
        });
      });
    }
    setSelectedSubCategories(updatedSelectedSubCategoriesForForm);
    console.log("selectedSubCategories: ", selectedSubCategories)
  };
  
  

  // Function to clear form data
  const clear = () => {
    setPlayerData({ name: '', club: '', infoEnglish: '', infoNorwegian: '', category: '' });
    setImageFiles([]);
    setImagePreviews([]);
  };

  // Handle form submission
  const handleFormSubmit = (e) => {
    e.preventDefault();

    const selectedCategoriesToSend = [];

    // Construct array of selected categories and subcategories
    for (const mainCategory in selectedSubCategoriesByCategory) {
      const subCategories = selectedSubCategoriesByCategory[mainCategory];

      subCategories.forEach((subCategory) => {
        selectedCategoriesToSend.push({
          main: mainCategory,
          sub: subCategory,
        });
      });
    }

    // Prepare updated player data
    const updatedPlayerData = {
      ...playerData,
      category: existingCategories.concat(selectedCategoriesToSend),
      images: existingImages.concat(imageFiles),
    };

    // Handle form submission
    handleSubmit(updatedPlayerData);
    handleCloseUpdatePlayer(false); // Close player update form
    clear(); // Clear form data
  };

  return (
    <form onSubmit={handleFormSubmit} encType="multipart/form-data">
      {/* Grid container for arranging form components */}
      <Grid container spacing={2}>
        {/* Grid item for player data fields */}
        <Grid item xs={12} sm={6}>
          <PlayerData playerData={playerData} handleInputChange={handleInputChange} />
        </Grid>
        {/* Grid item for category selection */}
        <Grid item xs={12} sm={6}>
          <CategorySelect
            selectedCategory={selectedCategory}
            showExistingCategories={player ? true :false}
            handleSelectChange={handleSelectChange}
            menuData={menuData}
            handleSubCategoryChange={(e) => handleSubCategoryChange(e, selectedCategory)}
            selectedSubCategoryValues={selectedSubCategories}
            existingCategories={existingCategories}
          />
        </Grid>
        {/* Grid item for image upload */}
        <Grid item xs={12} sm={6}>
          <ImageUpload
            imagePreviews={imagePreviews}
            showExistingImages={player ? true : false}
            handleImageChange={handleImageChange}
            handleRemoveImage={handleRemoveImage}
            existingImages={existingImages}
          />
        </Grid>
        {/* Grid item for form submission */}
        <Grid item xs={12} sm={6}>
          <Button variant="contained" color="primary" type="submit">
            {player ? "Update Player" : "Add Player"}
          </Button>
        </Grid>
      </Grid>
    </form>
  );
}

export default AddUpdatePlayerForm;
